func newAuthCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "auth",
		Short: "Manage authentication for Amazon Seller",
	}

	cmd.AddCommand(newAuthStatusCmd(flags))
	cmd.AddCommand(newAuthLogoutCmd(flags))

	return cmd
}

func newAuthStatusCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "status",
		Short: "Show authentication status",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return err
			}

			missing := missingRefreshTokenAuthInputs(cfg)
			cacheStatus := refreshTokenCacheStatus(cfg)
			configured := len(missing) == 0

			w := cmd.OutOrStdout()
			if flags.asJSON {
				out := map[string]any{
					"configured":       configured,
					"missing_env_vars": missing,
					"cache_status":     cacheStatus,
					"config":           cfg.Path,
				}
				return printJSONFiltered(w, out, flags)
			}

			if configured {
				fmt.Fprintf(w, "  %s Required auth environment variables present\n", green("OK"))
			} else {
				fmt.Fprintf(w, "  %s Missing required auth environment variables: %s\n", red("FAIL"), strings.Join(missing, ", "))
			}

			switch cacheStatus {
			case "valid":
				fmt.Fprintf(w, "  %s Access-token cache valid (expires %s)\n", green("OK"), cfg.TokenExpiry.Format(time.RFC3339))
			case "valid_no_expiry":
				fmt.Fprintf(w, "  %s Access-token cache present (no expiry info)\n", green("OK"))
			case "expired":
				fmt.Fprintf(w, "  %s Access-token cache expired; it will refresh on the next request\n", yellow("WARN"))
			default:
				if configured {
					fmt.Fprintf(w, "  %s Configured, access-token cache empty; the next request will mint one\n", yellow("WARN"))
				} else {
					fmt.Fprintf(w, "  %s Access-token cache empty\n", yellow("WARN"))
				}
			}
			return nil
		},
	}
}

func missingRefreshTokenAuthInputs(cfg *config.Config) []string {
	var missing []string
	if cfg.ClientID == "" {
		missing = append(missing, "SP_API_LWA_CLIENT_ID")
	}
	if cfg.ClientSecret == "" {
		missing = append(missing, "SP_API_LWA_CLIENT_SECRET")
	}
	if cfg.RefreshToken == "" {
		missing = append(missing, "SP_API_REFRESH_TOKEN")
	}
	return missing
}

func refreshTokenCacheStatus(cfg *config.Config) string {
	if cfg.AccessToken == "" {
		return "empty"
	}
	if cfg.TokenExpiry.IsZero() {
		return "valid_no_expiry"
	}
	if time.Now().Before(cfg.TokenExpiry) {
		return "valid"
	}
	return "expired"
}

func newAuthLogoutCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "logout",
		Short: "Remove stored access tokens",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return err
			}
			if err := cfg.ClearTokens(); err != nil {
				return fmt.Errorf("clearing tokens: %w", err)
			}
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"cleared": true,
					"note":    "environment variables are unchanged",
				}, flags)
			}
			fmt.Fprintln(cmd.OutOrStdout(), "Logged out. Stored access-token cache removed; environment variables are unchanged.")
			return nil
		},
	}
}
